inline Incb incb_value(char32_t cp) {
  int lo = 0, hi = (int)(sizeof(_incb_ranges) / sizeof(_incb_ranges[0])) - 1;
  while (lo <= hi) {
    int m = (lo + hi) / 2;
    if (cp < _incb_ranges[m].lo) hi = m - 1;
    else if (cp > _incb_ranges[m].hi) lo = m + 1;
    else return _incb_ranges[m].v;
  }
  return Incb::None;
}
inline bool is_incb_consonant(char32_t cp){return incb_value(cp)==Incb::Consonant;}
inline bool is_incb_extend(char32_t cp){return incb_value(cp)==Incb::Extend;}
inline bool is_incb_linker(char32_t cp){return incb_value(cp)==Incb::Linker;}

